public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
    java.util.Map<String, Integer> orderMap = new java.util.HashMap<>();
    orderMap.put("electronics", 0);
    orderMap.put("grocery", 1);
    orderMap.put("pharmacy", 2);
    orderMap.put("restaurant", 3);

    java.util.List<Integer> validIndices = new java.util.ArrayList<>();
    for (int i = 0; i < code.length; i++) {
        if (!isActive[i]) {
            continue;
        }
        String c = code[i];
        if (c == null || !c.matches("[a-zA-Z0-9_]+")) {
            continue;
        }
        String bl = businessLine[i];
        if (!orderMap.containsKey(bl)) {
            continue;
        }
        validIndices.add(i);
    }

    validIndices.sort((i, j) -> {
        int orderI = orderMap.get(businessLine[i]);
        int orderJ = orderMap.get(businessLine[j]);
        if (orderI != orderJ) {
            return Integer.compare(orderI, orderJ);
        }
        return code[i].compareTo(code[j]);
    });

    String[] result = new String[validIndices.size()];
    for (int k = 0; k < validIndices.size(); k++) {
        result[k] = code[validIndices.get(k)];
    }
    return result;
}
