            } else if ("pharmacy".equals(bl)) {
                pharmacy.add(c);
            } else if ("restaurant".equals(bl)) {
                restaurant.add(c);
            }
        }

        Collections.sort(electronics);
        Collections.sort(grocery);
        Collections.sort(pharmacy);
        Collections.sort(restaurant);

        int totalSize = electronics.size() + grocery.size() + pharmacy.size() + restaurant.size();
        String[] result = new String[totalSize];
        int index = 0;
        for (String s : electronics) {
            result[index++] = s;
        }
        for (String s : grocery) {
            result[index++] = s;
        }
        for (String s : pharmacy) {
            result[index++] = s;
        }
        for (String s : restaurant) {
            result[index++] = s;
        }
        return result;
    }
}
