public class CouponProcessor {
    public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
        int n = code.length;
        Set<String> validBusinessSet = new HashSet<>(Arrays.asList("electronics", "grocery", "pharmacy", "restaurant"));

        List<String[]> validCoupons = new ArrayList<>();

        for (int i = 0; i < n; i++) {
            if (!isActive[i]) {
                continue;
            }

            String bl = businessLine[i];
            if (!validBusinessSet.contains(bl)) {
                continue;
            }

            String c = code[i];
            if (c == null || c.isEmpty()) {
                continue;
            }
            if (!c.matches("[a-zA-Z0-9_]+")) {
                continue;
            }

            validCoupons.add(new String[]{bl, c});
        }

        Map<String, Integer> orderMap = new HashMap<>();
        orderMap.put("electronics", 0);
        orderMap.put("grocery", 1);
        orderMap.put("pharmacy", 2);
        orderMap.put("restaurant", 3);

        validCoupons.sort((a, b) -> {
            int orderA = orderMap.get(a[0]);
            int orderB = orderMap.get(b[0]);
            if (orderA != orderB) {
                return orderA - orderB;
            }
            return a[1].compareTo(b[1]);
